1	import { readFileSync } from "fs";
2	import { quote, claim, type Customer, type Item, type Damage } from "./claim-office.js";
3	
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policyStep: number; incident: { damages: Damage[] } };
6	type Step = QuoteStep | ClaimStep;
7	
8	type Scenario = {
9	  customer: Customer;
10	  steps: Step[];
11	};
12	
13	type StepResult = { premium?: number; payout?: number; remainingCap?: number };
14	
15	type Policy = { items: Item[]; accumulatedPaid: number };
16	
17	export function runScenario(scenario: Scenario): { results: StepResult[] } {
18	  const policiesByStep: Record<number, Policy> = {};
19	
20	  const handleStep = (step: Step, index: number): StepResult => {
21	    if (step.op === "quote") {
22	      policiesByStep[index] = { items: step.items, accumulatedPaid: 0 };
23	      return { premium: quote(scenario.customer, step.items) };
24	    }
25	    const policy = policiesByStep[step.policyStep] ?? { items: [], accumulatedPaid: 0 };
26	    const result = claim(policy.items, step.incident.damages, policy.accumulatedPaid);
27	    policy.accumulatedPaid += result.payout;
28	    return { payout: result.payout, remainingCap: result.remainingCap };
29	  };
30	
31	  return { results: scenario.steps.map(handleStep) };
32	}
33	
34	function main(): void {
35	  try {
36	    const input = readFileSync(0, "utf-8");
37	    const scenario = JSON.parse(input) as Scenario;
38	    const result = runScenario(scenario);
39	    process.stdout.write(JSON.stringify(result));
40	  } catch (err) {
41	    process.stderr.write(err instanceof Error ? err.message : String(err));
42	    process.exit(1);
43	  }
44	}
45	
46	if (process.argv[1]?.endsWith("cli.ts") || process.argv[1]?.endsWith("cli.js")) {
47	  main();
48	}
